1	// Building renderer — OWNED by Dev A
2	// "Dumb" instancer: takes a BuildingDescription produced by Gemini Vision and
3	// matérialises it in Three.js. No procedural decisions are made here — every
4	// dimension, position and color is determined by the AI agent.
5	
6	'use client';
7	
8	import { useMemo } from 'react';
9	import { Edges } from '@react-three/drei';
10	import { BufferAttribute, BufferGeometry } from 'three';
11	import { useSceneVision } from './vision/useSceneVision';
12	import type {
13	  Facade,
14	  FacadeOrientation,
15	  Opening,
16	  Roof,
17	  RoofFeature,
18	  Volume,
19	} from './vision/buildingTypes';
20	
21	const EDGE_COLOR = '#111111';
22	const EDGE_THRESHOLD = 15;
23	const EDGE_LINE_WIDTH = 1.5;
24	
25	const FACADE_TRANSFORMS: Record<
26	  FacadeOrientation,
27	  { rotY: number; offsetAxis: 'x' | 'z'; sign: 1 | -1 }
28	> = {
29	  south: { rotY: 0, offsetAxis: 'z', sign: 1 },
30	  north: { rotY: Math.PI, offsetAxis: 'z', sign: -1 },
31	  east: { rotY: -Math.PI / 2, offsetAxis: 'x', sign: 1 },
32	  west: { rotY: Math.PI / 2, offsetAxis: 'x', sign: -1 },
33	};
34	
35	export function BuildingRenderer() {
36	  const { building } = useSceneVision();
37	  if (!building) return null;
38	  return (
39	    <group>
40	      <Ground />
41	      {building.volumes.map((v, i) => (
42	        <VolumeMesh key={i} volume={v} trimColor={building.trimColor} />
43	      ))}
44	    </group>
45	  );
46	}
47	
48	function Ground() {
49	  return (
50	    <mesh position={[0, 0, 0]} rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
51	      <planeGeometry args={[80, 80]} />
52	      <meshToonMaterial color="#fafafa" />
53	    </mesh>
54	  );
55	}
56	
57	function VolumeMesh({ volume, trimColor }: { volume: Volume; trimColor: string }) {
58	  const totalHeight = volume.storeyCount * volume.storeyHeightM;
59	  return (
60	    <group position={[volume.centerX, 0, volume.centerZ]}>
61	      {/* Walls */}
62	      <mesh position={[0, totalHeight / 2, 0]} castShadow receiveShadow>
63	        <boxGeometry args={[volume.width, totalHeight, volume.depth]} />
64	        <meshToonMaterial color={volume.wallColor} />
65	        <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={EDGE_LINE_WIDTH} />
66	      </mesh>
67	
68	      {/* Storey divider bands */}
69	      {Array.from({ length: volume.storeyCount - 1 }, (_, i) => (
70	        <Band
71	          key={i}
72	          y={(i + 1) * volume.storeyHeightM}
73	          width={volume.width}
74	          depth={volume.depth}
75	          color={trimColor}
76	        />
77	      ))}
78	
79	      {/* Facades — windows/doors */}
80	      {volume.facades.map((facade) => (
81	        <FacadeDecor
82	          key={facade.orientation}
83	          facade={facade}
84	          volumeWidth={volume.width}
85	          volumeDepth={volume.depth}
86	          storeyHeight={volume.storeyHeightM}
87	          trimColor={trimColor}
88	        />
89	      ))}
90	
91	      {/* Roof + features */}
92	      <RoofMesh
93	        roof={volume.roof}
94	        wallTopY={totalHeight}
95	        width={volume.width}
96	        depth={volume.depth}
97	        wallColor={volume.wallColor}
98	      />
99	    </group>
100	  );
101	}
102	
103	function Band({ y, width, depth, color }: { y: number; width: number; depth: number; color: string }) {
104	  return (
105	    <mesh position={[0, y, 0]}>
106	      <boxGeometry args={[width + 0.06, 0.1, depth + 0.06]} />
107	      <meshToonMaterial color={color} />
108	      <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={1} />
109	    </mesh>
110	  );
111	}
112	
113	function FacadeDecor({
114	  facade,
115	  volumeWidth,
116	  volumeDepth,
117	  storeyHeight,
118	  trimColor,
119	}: {
120	  facade: Facade;
121	  volumeWidth: number;
122	  volumeDepth: number;
123	  storeyHeight: number;
124	  trimColor: string;
125	}) {
126	  const t = FACADE_TRANSFORMS[facade.orientation];
127	  const facadeWidth = t.offsetAxis === 'x' ? volumeDepth : volumeWidth;
128	  const offsetDistance = t.offsetAxis === 'x' ? volumeWidth / 2 : volumeDepth / 2;
129	
130	  const position: [number, number, number] = [
131	    t.offsetAxis === 'x' ? t.sign * (offsetDistance + 0.005) : 0,
132	    0,
133	    t.offsetAxis === 'z' ? t.sign * (offsetDistance + 0.005) : 0,
134	  ];
135	
136	  return (
137	    <group position={position} rotation={[0, t.rotY, 0]}>
138	      {facade.openings.map((op, i) => (
139	        <OpeningMesh
140	          key={i}
141	          opening={op}
142	          facadeWidth={facadeWidth}
143	          storeyHeight={storeyHeight}
144	          trimColor={trimColor}
145	        />
146	      ))}
147	    </group>
148	  );
149	}
150	
151	function OpeningMesh({
152	  opening,
153	  facadeWidth,
154	  storeyHeight,
155	  trimColor,
156	}: {
157	  opening: Opening;
158	  facadeWidth: number;
159	  storeyHeight: number;
160	  trimColor: string;
161	}) {
162	  const x = (opening.horizontalPosition - 0.5) * facadeWidth;
163	  const baseY = opening.storey * storeyHeight;
164	  const isDoor = opening.type === 'door' || opening.type === 'garage_door';
165	  const sillOffset = isDoor ? 0 : 0.9;
166	  const y = baseY + sillOffset + opening.height / 2;
167	
168	  const frameThickness = 0.05;
169	
170	  return (
171	    <group position={[x, y, 0]}>
172	      <mesh position={[0, 0, 0.025]}>
173	        <boxGeometry args={[opening.width + 0.08, opening.height + 0.08, 0.05]} />
174	        <meshToonMaterial color={trimColor} />
175	        <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={1} />
176	      </mesh>
177	      <mesh position={[0, 0, 0.06]}>
178	        <planeGeometry args={[opening.width - frameThickness, opening.height - frameThickness]} />
179	        <meshToonMaterial color={isDoor ? '#3a3a3a' : '#5b7894'} />
180	      </mesh>
181	      {opening.hasShutters && !isDoor && (
182	        <>
183	          <mesh position={[-(opening.width / 2 + 0.12), 0, 0.04]}>
184	            <boxGeometry args={[opening.width * 0.18, opening.height + 0.05, 0.03]} />
185	            <meshToonMaterial color={trimColor} />
186	            <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={1} />
187	          </mesh>
188	          <mesh position={[opening.width / 2 + 0.12, 0, 0.04]}>
189	            <boxGeometry args={[opening.width * 0.18, opening.height + 0.05, 0.03]} />
190	            <meshToonMaterial color={trimColor} />
191	            <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={1} />
192	          </mesh>
193	        </>
194	      )}
195	      {isDoor && (
196	        <mesh position={[opening.width * 0.32, -opening.height * 0.05, 0.07]}>
197	          <sphereGeometry args={[0.04, 8, 8]} />
198	          <meshStandardMaterial color="#222" metalness={0.7} roughness={0.3} />
199	        </mesh>
200	      )}
201	    </group>
202	  );
203	}
204	
205	function RoofMesh({
206	  roof,
207	  wallTopY,
208	  width,
209	  depth,
210	  wallColor,
211	}: {
212	  roof: Roof;
213	  wallTopY: number;
214	  width: number;
215	  depth: number;
216	  wallColor: string;
217	}) {
218	  if (roof.type === 'flat') {
219	    return (
220	      <>
221	        <mesh position={[0, wallTopY + 0.05, 0]} castShadow>
222	          <boxGeometry args={[width + roof.overhangM * 2, 0.1, depth + roof.overhangM * 2]} />
223	          <meshToonMaterial color={roof.color} />
224	          <Edges threshold={EDGE_THRESHOLD} color={EDGE_COLOR} lineWidth={EDGE_LINE_WIDTH} />
225	        </mesh>
226	        {roof.features.map((f, i) => (
227	          <RoofFeatureMesh key={i} feature={f} baseY={wallTopY + 0.1} />
228	        ))}
229	      </>
230	    );
231	  }
232	
233	  // Pitched roof — rise from eave to ridge
234	  const halfBaseEave =
235	    roof.ridgeAxis === 'x' ? depth / 2 + roof.overhangM : width / 2 + roof.overhangM;
236	  const ridgeRise = halfBaseEave * Math.tan((roof.pitchDeg * Math.PI) / 180);
237	  const ridgeY = wallTopY + ridgeRise;
238	  const longExtent =
239	    roof.ridgeAxis === 'x' ? width / 2 + roof.overhangM : depth / 2 + roof.overhangM;
240	
241	  return (
242	    <group>
243	      <RoofPan
244	        ridgeAxis={roof.ridgeAxis}
245	        side="positive"
246	        wallTopY={wallTopY}
247	        ridgeY={ridgeY}
248	        halfBase={halfBaseEave}
249	        longBase={longExtent}
250	        color={roof.color}
251	      />
252	      <RoofPan
253	        ridgeAxis={roof.ridgeAxis}
254	        side="negative"
255	        wallTopY={wallTopY}
256	        ridgeY={ridgeY}
257	        halfBase={halfBaseEave}
258	        longBase={longExtent}
259	        color={roof.color}
260	      />
261	      {roof.type !== 'hip' && roof.type !== 'shed' && (
262	        <>
263	          <Gable
264	            ridgeAxis={roof.ridgeAxis}
265	            side="positive"
266	            wallTopY={wallTopY}
267	            ridgeY={ridgeY}
268	            width={width}
269	            depth={depth}
270	            color={wallColor}
271	          />
272	          <Gable
273	            ridgeAxis={roof.ridgeAxis}
274	            side="negative"
275	            wallTopY={wallTopY}
276	            ridgeY={ridgeY}
277	            width={width}
278	            depth={depth}
279	            color={wallColor}
280	          />
281	        </>
282	      )}
283	      {roof.features.map((f, i) => (
284	        <RoofFeatureMesh key={i} feature={f} baseY={wallTopY} />
285	      ))}
286	    </group>
287	  );
288	}
289	
290	function RoofPan({
291	  ridgeAxis,
292	  side,
293	  wallTopY,
294	  ridgeY,
295	  halfBase,
296	  longBase,
297	  color,
298	}: {
299	  ridgeAxis: 'x' | 'z';
300	  side: 'positive' | 'negative';
301	  wallTopY: number;
302	  ridgeY: number;
303	  halfBase: number;
304	  longBase: number;
305	  color: string;
306	}) {
307	  const sign = side === 'positive' ? 1 : -1;
308	  const geom = useMemo(() => {
309	    let positions: number[];
310	    if (ridgeAxis === 'x') {
311	      // Ridge along X (z=0). Pan goes from eave at z=±halfBase up to ridge at z=0.
312	      const eaveZ = sign * halfBase;
313	      // Order: bottom-left, bottom-right, top-right, top-left (CCW from outside)
314	      positions =
315	        sign > 0
316	          ? [
317	              -longBase, wallTopY, eaveZ,
318	              longBase, wallTopY, eaveZ,
319	              longBase, ridgeY, 0,
320	              -longBase, ridgeY, 0,
321	            ]
322	          : [
323	              longBase, wallTopY, eaveZ,
324	              -longBase, wallTopY, eaveZ,
325	              -longBase, ridgeY, 0,
326	              longBase, ridgeY, 0,
327	            ];
328	    } else {
329	      // Ridge along Z (x=0). Pan goes from eave at x=±halfBase up to ridge at x=0.
330	      const eaveX = sign * halfBase;
331	      positions =
332	        sign > 0
333	          ? [
334	              eaveX, wallTopY, longBase,
335	              eaveX, wallTopY, -longBase,
336	              0, ridgeY, -longBase,
337	              0, ridgeY, longBase,
338	            ]
339	          : [
340	              eaveX, wallTopY, -longBase,
341	              eaveX, wallTopY, longBase,
342	              0, ridgeY, longBase,
343	              0, ridgeY, -longBase,
344	            ];
345	    }
346	    const g = new BufferGeometry();
347	    g.setAttribute('position', new BufferAttribute(new Float32Array(positions), 3));
