      'Heating types: oil (Öl, Heizöl), gas (Gas, Erdgas), heatpump (Wärmepumpe, pompe à chaleur), other. ' +
      'Convert annual EV km if expressed monthly or weekly.',
    prompt: text,
  });
  return output;
}

export { MODEL_FAST, MODEL_QUALITY };

