export async function generateTrellisModel(input: TrellisInput): Promise<TrellisResult> {
  ensureConfigured();

  // 1. Upload the input image to fal storage so trellis can fetch it.
  // Using Blob (web-standard, supported in Node 20+) instead of File — File's
  // constructor signature differs subtly between runtimes, and fal.storage
  // only needs something Blob-like with the right MIME type.
  const blob = new Blob([new Uint8Array(input.image)], { type: 'image/png' });
  let imageUrl: string;
  try {
    imageUrl = await fal.storage.upload(blob);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    throw new Error(`fal.storage.upload failed: ${msg}`);
  }

  // 2. Subscribe to the queue and wait for the GLB. Trellis-2 takes ~30-60s.
  // Defaults from the docs except: target a web-friendly mesh size (30k verts,
  // 1024px texture) so the GLB streams quickly into the Three.js scene.
  try {
    const result = await fal.subscribe('fal-ai/trellis-2', {
      input: {
        image_url: imageUrl,
        decimation_target: 30000,
        texture_size: '1024',
        resolution: '1024',
      },
      logs: false,
    });
    const glbUrl = result.data?.model_glb?.url;
    if (!glbUrl) throw new Error('trellis returned no model_glb url');
    return { glbUrl, requestId: result.requestId };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    // Surface fal-side validation errors (often HTTP 422 with body details).
    const detail =
      err && typeof err === 'object' && 'body' in err
        ? ` body=${JSON.stringify((err as { body: unknown }).body)}`
        : '';
    throw new Error(`fal.subscribe(trellis-2) failed: ${msg}${detail}`);
  }
}

