  const submitRes = await rawFetch(`${QUEUE_BASE}/${MODEL_ID}`, {
    method: 'POST',
    headers: {
      Authorization: authHeader(),
      'content-type': 'application/json',
    },
    body: JSON.stringify({
      image_url: file_url,
      decimation_target: 30000,
      texture_size: '1024',
      resolution: '1024',
    }),
  });
