// fetch with its caching/instrumentation proxy, which somehow makes fal reply
// with HTTP 403 "User is locked. Reason: Exhausted balance." even when the
// account has plenty of credit (verified via plain Node fetch + curl using
// the exact same key — both return 200). Going through undici directly
// sidesteps Next's wrapper entirely.

import { fetch as rawFetch } from 'undici';

const STORAGE_INITIATE_URL = 'https://rest.alpha.fal.ai/storage/upload/initiate';

